solutionCode:
function listEnabledExtensions(flags) {
  const enabled = [];
  if (flags.nonTransferable) enabled.push('NonTransferable');
  if (flags.transferHook) enabled.push('TransferHook');
  if (flags.confidential) enabled.push('ConfidentialTransfer');
  return {
    enabled,
    count: enabled.length,
  };
}

testCode:
const r = listEnabledExtensions({ nonTransferable: true, transferHook: false, confidential: true });
assert(r.count === 2, 'count mismatch');
assert(r.enabled[0] === 'NonTransferable', 'first extension mismatch');
assert(r.enabled[1] === 'ConfidentialTransfer', 'second extension mismatch');
